import{_ as e,o as t,c as o,ag as n}from"./chunks/framework.BCsDra3S.js";const d=JSON.parse('{"title":"What is MagiC?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-magic.md","filePath":"guide/what-is-magic.md"}'),s={name:"guide/what-is-magic.md"};function i(r,a,l,h,p,g){return t(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="what-is-magic" tabindex="-1">What is MagiC? <a class="header-anchor" href="#what-is-magic" aria-label="Permalink to &quot;What is MagiC?&quot;">​</a></h1><p>MagiC is an open-source framework for <strong>managing fleets of AI workers</strong>. Think Kubernetes for AI agents — it doesn&#39;t build agents, it manages any agents built with any tool through an open protocol.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Most AI frameworks force you to build agents in their way:</p><ul><li><strong>CrewAI</strong> — Python only, tightly coupled roles</li><li><strong>AutoGen</strong> — Python only, GroupChat model</li><li><strong>LangGraph</strong> — Python only, graph model</li></ul><p>None of them answer: <em>what happens when you need 10 workers in production, each built differently, and you want to monitor costs, route tasks intelligently, and handle failures?</em></p><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>MagiC is the <strong>orchestration layer above your agents</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         You (CEO)</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>        MagiC Server           ← routing, monitoring, cost control</span></span>
<span class="line"><span>       /    │    │    \\</span></span>
<span class="line"><span>  CrewAI  LangChain  Custom   ← any framework, any language</span></span>
<span class="line"><span>  Agent    Chain     Bot</span></span></code></pre></div><p>Your CrewAI agent becomes a MagiC worker. Your LangChain chain becomes a MagiC worker. They join the same organization and work together.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><ul><li><strong>Workers</strong> — any HTTP server that registers capabilities and accepts tasks</li><li><strong>Tasks</strong> — units of work routed to the best available worker</li><li><strong>Workflows</strong> — multi-step DAGs with parallel execution and failure handling</li><li><strong>Organizations</strong> — groups of workers with shared budgets and policies</li><li><strong>Protocol (MCP²)</strong> — JSON over HTTP; workers respond with <code>task.complete</code> or <code>task.fail</code></li></ul>`,12)])])}const u=e(s,[["render",i]]);export{d as __pageData,u as default};
